202	    const result = TASKRUNSFORPLRCACHE[cacheKey];
203	    if (result) {
204	      PLRTaskRuns = result;
205	      taskRunsLoaded = true;
206	    } else if (InFlightStoreForTaskRunsForPLR[cacheKey]) {
207	      PLRTaskRuns = [];
208	      taskRunsLoaded = true;
209	      InFlightStoreForTaskRunsForPLR[cacheKey] = true;
210	    } else {
211	      return (
212	        <PipelineRowWithTaskRunsFetch
213	          obj={obj}
214	          activeColumnIDs={activeColumnIDs}
215	          currentUser={currentUser}
216	        />
217	      );
218	    }
219	    return (
220	      <PipelineRowTable
221	        obj={obj}
222	        PLRTaskRuns={PLRTaskRuns}
223	        taskRunsLoaded={taskRunsLoaded}
224	        taskRunStatusObj={undefined}
225	        activeColumnIDs={activeColumnIDs}
226	        currentUser={currentUser}
227	      />
228	    );
229	  });
