237	    (obj?.latestRun?.status?.childReferences ?? []).length > 0
238	  ) {
239	    return (
240	      <PipelineRowWithTaskRuns
241	        obj={obj}
242	        activeColumnIDs={activeColumnIDs}
243	        currentUser={currentUser}
