250	    <PipelineRowWithoutTaskRuns
251	      obj={obj}
252	      taskRunStatusObj={taskRunStatusObj}
253	      activeColumnIDs={activeColumnIDs}
254	      currentUser={currentUser}
255	    />
256	  );
257	};
